/* 前置条件：header-banner 需要这两行 */
.header-banner {
  position: relative;
  overflow: hidden;
}

/* ===== 浮动闪烁粒子 ===== */
.header-sparkle {
  position: absolute;
  width: 4px;
  height: 4px;
  background: rgba(255, 255, 255, 0.6);
  border-radius: 50%;
  animation: sparkle-float 3s ease-in-out infinite;
}

.header-sparkle:nth-child(1) {
  top: 30%;
  left: 15%;
  animation-delay: 0s;
}

.header-sparkle:nth-child(2) {
  top: 20%;
  right: 20%;
  animation-delay: 1s;
  width: 3px;
  height: 3px;
}

.header-sparkle:nth-child(3) {
  bottom: 30%;
  left: 25%;
  animation-delay: 2s;
  width: 5px;
  height: 5px;
}

@keyframes sparkle-float {
  0%, 100% {
    opacity: 0.4;
    transform: translateY(0) scale(1);
  }
  50% {
    opacity: 1;
    transform: translateY(-8px) scale(1.3);
  }
}

/* ===== 头像呼吸缩放 ===== */
.ip-container {
  position: relative;
  z-index: 2;
  /* 双层阴影：蓝色辉光 + 白色光环 */
  box-shadow:
    0 4px 20px rgba(64, 102, 224, 0.25),
    0 0 0 4px rgba(255, 255, 255, 0.3);
  animation: avatar-breathe 4s ease-in-out infinite;
}

@keyframes avatar-breathe {
  0%, 100% {
    transform: scale(1);
    box-shadow:
      0 4px 20px rgba(64, 102, 224, 0.25),
      0 0 0 4px rgba(255, 255, 255, 0.3);
  }
  50% {
    transform: scale(1.03);
    box-shadow:
      0 6px 28px rgba(64, 102, 224, 0.3),
      0 0 0 6px rgba(255, 255, 255, 0.25);
  }
}

/* ===== 旋转虚线环 ===== */
.ip-container::after {
  content: '';
  position: absolute;
  inset: -6px;
  border-radius: 50%;
  border: 2px dashed rgba(255, 255, 255, 0.35);
  animation: ring-spin 20s linear infinite;
}

@keyframes ring-spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

/* 前置条件 */
.header-banner {
  position: relative;
  overflow: hidden;
}

/* ===== 右上角白色光球 ===== */
.header-banner::before {
  content: '';
  position: absolute;
  top: -60px;
  right: -40px;
  width: 180px;
  height: 180px;
  background: radial-gradient(
    circle,
    rgba(255, 255, 255, 0.12) 0%,
    transparent 70%
  );
  border-radius: 50%;
}

/* ===== 左下角暖黄光球 ===== */
.header-banner::after {
  content: '';
  position: absolute;
  bottom: -30px;
  left: -20px;
  width: 120px;
  height: 120px;
  background: radial-gradient(
    circle,
    rgba(250, 204, 21, 0.15) 0%,
    transparent 70%
  );
  border-radius: 50%;
}

